6	static GLenum glCheckError_(const char *file, int line)
7	{
8	    GLenum errorCode;
9	    while ((errorCode = glGetError()) != GL_NO_ERROR)
10	    {
11	        const char* error;
12	        switch (errorCode)
13	        {
14	            case GL_INVALID_ENUM:                  error = "INVALID_ENUM"; break;
15	            case GL_INVALID_VALUE:                 error = "INVALID_VALUE"; break;
16	            case GL_INVALID_OPERATION:             error = "INVALID_OPERATION"; break;
17	            case GL_STACK_OVERFLOW:                error = "STACK_OVERFLOW"; break;
18	            case GL_STACK_UNDERFLOW:               error = "STACK_UNDERFLOW"; break;
19	            case GL_OUT_OF_MEMORY:                 error = "OUT_OF_MEMORY"; break;
20	            case GL_INVALID_FRAMEBUFFER_OPERATION: error = "INVALID_FRAMEBUFFER_OPERATION"; break;
21	            default:                               error = "UNKNOWN"; break;
22	        }
23	        fprintf(stderr, "ERROR: OpenGL \"%s\" in file \"%s\" (line %d)\n", error, file, line);
24	    }
25	    return errorCode;
26	}
27	#define glCheckError() glCheckError_(__FILE__, __LINE__)
28	
29	#endif // _UTILS_H
