1354	            n /= norm(n);
1355	
1356	            model->attrib.normals.push_back( n.x );
1357	            model->attrib.normals.push_back( n.y );
1358	            model->attrib.normals.push_back( n.z );
1359	
1360	            size_t normal_index = (model->attrib.normals.size() / 3) - 1;
1361	            normal_indices[vertex_index] = normal_index;
1362	        }
1363	
1364	        // Escrevemos os índices das normais para os vértices dos triângulos deste smoothing group
1365	        for (size_t shape = 0; shape < model->shapes.size(); ++shape)
1366	        {
1367	            size_t num_triangles = model->shapes[shape].mesh.num_face_vertices.size();
1368	
1369	            for (size_t triangle = 0; triangle < num_triangles; ++triangle)
1370	            {
1371	                unsigned int sgroup_tri = model->shapes[shape].mesh.smoothing_group_ids[triangle];
1372	
1373	                if (sgroup_tri != sgroup)
1374	                    continue;
1375	
1376	                for (size_t vertex = 0; vertex < 3; ++vertex)
1377	                {
1378	                    tinyobj::index_t idx = model->shapes[shape].mesh.indices[3*triangle + vertex];
1379	                    model->shapes[shape].mesh.indices[3*triangle + vertex].normal_index =
1380	                        normal_indices[ idx.vertex_index ];
1381	                }
1382	            }
1383	        }
1384	
1385	    }
1386	}
