1388	// Constrói triângulos para futura renderização a partir de um ObjModel.
1389	void BuildTrianglesAndAddToVirtualScene(ObjModel* model)
1390	{
1391	    GLuint vertex_array_object_id;
1392	    glGenVertexArrays(1, &vertex_array_object_id);
1393	    glBindVertexArray(vertex_array_object_id);
1394	
1395	    std::vector<GLuint> indices;
1396	    std::vector<float>  model_coefficients;
1397	    std::vector<float>  normal_coefficients;
1398	    std::vector<float>  texture_coefficients;
1399	
1400	    for (size_t shape = 0; shape < model->shapes.size(); ++shape)
1401	    {
1402	        size_t first_index = indices.size();
1403	        size_t num_triangles = model->shapes[shape].mesh.num_face_vertices.size();
1404	
1405	        const float minval = std::numeric_limits<float>::min();
1406	        const float maxval = std::numeric_limits<float>::max();
1407	
1408	        glm::vec3 bbox_min = glm::vec3(maxval,maxval,maxval);
1409	        glm::vec3 bbox_max = glm::vec3(minval,minval,minval);
1410	
1411	        for (size_t triangle = 0; triangle < num_triangles; ++triangle)
1412	        {
1413	            assert(model->shapes[shape].mesh.num_face_vertices[triangle] == 3);
1414	
1415	            for (size_t vertex = 0; vertex < 3; ++vertex)
1416	            {
1417	                tinyobj::index_t idx = model->shapes[shape].mesh.indices[3*triangle + vertex];
1418	
1419	                indices.push_back(first_index + 3*triangle + vertex);
1420	
1421	                const float vx = model->attrib.vertices[3*idx.vertex_index + 0];
1422	                const float vy = model->attrib.vertices[3*idx.vertex_index + 1];
1423	                const float vz = model->attrib.vertices[3*idx.vertex_index + 2];
1424	                //printf("tri %d vert %d = (%.2f, %.2f, %.2f)\n", (int)triangle, (int)vertex, vx, vy, vz);
1425	                model_coefficients.push_back( vx ); // X
1426	                model_coefficients.push_back( vy ); // Y
1427	                model_coefficients.push_back( vz ); // Z
1428	                model_coefficients.push_back( 1.0f ); // W
1429	
1430	                bbox_min.x = std::min(bbox_min.x, vx);
1431	                bbox_min.y = std::min(bbox_min.y, vy);
1432	                bbox_min.z = std::min(bbox_min.z, vz);
1433	                bbox_max.x = std::max(bbox_max.x, vx);
1434	                bbox_max.y = std::max(bbox_max.y, vy);
1435	                bbox_max.z = std::max(bbox_max.z, vz);
1436	
1437	                // Inspecionando o código da tinyobjloader, o aluno Bernardo
1438	                // Sulzbach (2017/1) apontou que a maneira correta de testar se
1439	                // existem normais e coordenadas de textura no ObjModel é
1440	                // comparando se o índice retornado é -1. Fazemos isso abaixo.
1441	
1442	                if ( idx.normal_index != -1 )
1443	                {
1444	                    const float nx = model->attrib.normals[3*idx.normal_index + 0];
1445	                    const float ny = model->attrib.normals[3*idx.normal_index + 1];
1446	                    const float nz = model->attrib.normals[3*idx.normal_index + 2];
1447	                    normal_coefficients.push_back( nx ); // X
1448	                    normal_coefficients.push_back( ny ); // Y
1449	                    normal_coefficients.push_back( nz ); // Z
1450	                    normal_coefficients.push_back( 0.0f ); // W
1451	                }
1452	
1453	                if ( idx.texcoord_index != -1 )
1454	                {
1455	                    const float u = model->attrib.texcoords[2*idx.texcoord_index + 0];
1456	                    const float v = model->attrib.texcoords[2*idx.texcoord_index + 1];
1457	                    texture_coefficients.push_back( u );
1458	                    texture_coefficients.push_back( v );
1459	                }
1460	                
1461	            }
1462	        }
1463	
1464	        size_t last_index = indices.size() - 1;
1465	
1466	        SceneObject theobject;
1467	        theobject.name           = model->shapes[shape].name;
1468	        theobject.first_index    = first_index; // Primeiro índice
1469	        theobject.num_indices    = last_index - first_index + 1; // Número de indices
1470	        theobject.rendering_mode = GL_TRIANGLES;       // Índices correspondem ao tipo de rasterização GL_TRIANGLES.
1471	        theobject.vertex_array_object_id = vertex_array_object_id;
1472	
1473	        theobject.bbox_min = bbox_min;
1474	        theobject.bbox_max = bbox_max;
1475	
1476	        g_VirtualScene[model->shapes[shape].name] = theobject;
1477	    }
1478	
1479	    GLuint VBO_model_coefficients_id;
1480	    glGenBuffers(1, &VBO_model_coefficients_id);
1481	    glBindBuffer(GL_ARRAY_BUFFER, VBO_model_coefficients_id);
1482	    glBufferData(GL_ARRAY_BUFFER, model_coefficients.size() * sizeof(float), NULL, GL_STATIC_DRAW);
1483	    glBufferSubData(GL_ARRAY_BUFFER, 0, model_coefficients.size() * sizeof(float), model_coefficients.data());
1484	    GLuint location = 0; // "(location = 0)" em "shader_vertex.glsl"
1485	    GLint  number_of_dimensions = 4; // vec4 em "shader_vertex.glsl"
1486	    glVertexAttribPointer(location, number_of_dimensions, GL_FLOAT, GL_FALSE, 0, 0);
1487	    glEnableVertexAttribArray(location);
1488	    glBindBuffer(GL_ARRAY_BUFFER, 0);
1489	
1490	    if ( !normal_coefficients.empty() )
1491	    {
1492	        GLuint VBO_normal_coefficients_id;
1493	        glGenBuffers(1, &VBO_normal_coefficients_id);
1494	        glBindBuffer(GL_ARRAY_BUFFER, VBO_normal_coefficients_id);
1495	        glBufferData(GL_ARRAY_BUFFER, normal_coefficients.size() * sizeof(float), NULL, GL_STATIC_DRAW);
1496	        glBufferSubData(GL_ARRAY_BUFFER, 0, normal_coefficients.size() * sizeof(float), normal_coefficients.data());
1497	        location = 1; // "(location = 1)" em "shader_vertex.glsl"
1498	        number_of_dimensions = 4; // vec4 em "shader_vertex.glsl"
1499	        glVertexAttribPointer(location, number_of_dimensions, GL_FLOAT, GL_FALSE, 0, 0);
1500	        glEnableVertexAttribArray(location);
1501	        glBindBuffer(GL_ARRAY_BUFFER, 0);
1502	    }
1503	
1504	    if ( !texture_coefficients.empty() )
1505	    {
1506	        GLuint VBO_texture_coefficients_id;
1507	        glGenBuffers(1, &VBO_texture_coefficients_id);
1508	        glBindBuffer(GL_ARRAY_BUFFER, VBO_texture_coefficients_id);
1509	        glBufferData(GL_ARRAY_BUFFER, texture_coefficients.size() * sizeof(float), NULL, GL_STATIC_DRAW);
1510	        glBufferSubData(GL_ARRAY_BUFFER, 0, texture_coefficients.size() * sizeof(float), texture_coefficients.data());
1511	        location = 2; // "(location = 1)" em "shader_vertex.glsl"
1512	        number_of_dimensions = 2; // vec2 em "shader_vertex.glsl"
1513	        glVertexAttribPointer(location, number_of_dimensions, GL_FLOAT, GL_FALSE, 0, 0);
1514	        glEnableVertexAttribArray(location);
1515	        glBindBuffer(GL_ARRAY_BUFFER, 0);
1516	    }
1517	
1518	    GLuint indices_id;
1519	    glGenBuffers(1, &indices_id);
1520	
1521	    // "Ligamos" o buffer. Note que o tipo agora é GL_ELEMENT_ARRAY_BUFFER.
1522	    glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, indices_id);
1523	    glBufferData(GL_ELEMENT_ARRAY_BUFFER, indices.size() * sizeof(GLuint), NULL, GL_STATIC_DRAW);
1524	    glBufferSubData(GL_ELEMENT_ARRAY_BUFFER, 0, indices.size() * sizeof(GLuint), indices.data());
1525	    // glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, 0); // XXX Errado!
1526	    //
1527	
1528	    // "Desligamos" o VAO, evitando assim que operações posteriores venham a
1529	    // alterar o mesmo. Isso evita bugs.
1530	    glBindVertexArray(0);
1531	}
