1533	// Carrega um Vertex Shader de um arquivo GLSL. Veja definição de LoadShader() abaixo.
1534	GLuint LoadShader_Vertex(const char* filename)
1535	{
1536	    // Criamos um identificador (ID) para este shader, informando que o mesmo
1537	    // será aplicado nos vértices.
1538	    GLuint vertex_shader_id = glCreateShader(GL_VERTEX_SHADER);
1539	
1540	    // Carregamos e compilamos o shader
1541	    LoadShader(filename, vertex_shader_id);
1542	
1543	    // Retorna o ID gerado acima
1544	    return vertex_shader_id;
1545	}
