1561	// Função auxilar, utilizada pelas duas funções acima. Carrega código de GPU de
1562	// um arquivo GLSL e faz sua compilação.
1563	void LoadShader(const char* filename, GLuint shader_id)
1564	{
1565	    // Lemos o arquivo de texto indicado pela variável "filename"
1566	    // e colocamos seu conteúdo em memória, apontado pela variável
1567	    // "shader_string".
1568	    std::ifstream file;
1569	    try {
1570	        file.exceptions(std::ifstream::failbit);
1571	        file.open(filename);
1572	    } catch ( std::exception& e ) {
1573	        fprintf(stderr, "ERROR: Cannot open file \"%s\".\n", filename);
1574	        std::exit(EXIT_FAILURE);
1575	    }
1576	    std::stringstream shader;
1577	    shader << file.rdbuf();
1578	    std::string str = shader.str();
1579	    const GLchar* shader_string = str.c_str();
1580	    const GLint   shader_string_length = static_cast<GLint>( str.length() );
1581	
1582	    // Define o código do shader GLSL, contido na string "shader_string"
1583	    glShaderSource(shader_id, 1, &shader_string, &shader_string_length);
1584	
1585	    // Compila o código do shader GLSL (em tempo de execução)
1586	    glCompileShader(shader_id);
1587	
1588	    // Verificamos se ocorreu algum erro ou "warning" durante a compilação
1589	    GLint compiled_ok;
1590	    glGetShaderiv(shader_id, GL_COMPILE_STATUS, &compiled_ok);
1591	
1592	    GLint log_length = 0;
1593	    glGetShaderiv(shader_id, GL_INFO_LOG_LENGTH, &log_length);
1594	
1595	    // Alocamos memória para guardar o log de compilação.
1596	    // A chamada "new" em C++ é equivalente ao "malloc()" do C.
1597	    GLchar* log = new GLchar[log_length];
1598	    glGetShaderInfoLog(shader_id, log_length, &log_length, log);
1599	
1600	    // Imprime no terminal qualquer erro ou "warning" de compilação
1601	    if ( log_length != 0 )
1602	    {
1603	        std::string  output;
1604	
1605	        if ( !compiled_ok )
1606	        {
1607	            output += "ERROR: OpenGL compilation of \"";
1608	            output += filename;
1609	            output += "\" failed.\n";
1610	            output += "== Start of compilation log\n";
1611	            output += log;
1612	            output += "== End of compilation log\n";
1613	        }
1614	        else
1615	        {
1616	            output += "WARNING: OpenGL compilation of \"";
1617	            output += filename;
1618	            output += "\".\n";
1619	            output += "== Start of compilation log\n";
1620	            output += log;
1621	            output += "== End of compilation log\n";
1622	        }
1623	
1624	        fprintf(stderr, "%s", output.c_str());
1625	    }
1626	
1627	    // A chamada "delete" em C++ é equivalente ao "free()" do C
1628	    delete [] log;
1629	}
