1631	// Esta função cria um programa de GPU, o qual contém obrigatoriamente um
1632	// Vertex Shader e um Fragment Shader.
1633	GLuint CreateGpuProgram(GLuint vertex_shader_id, GLuint fragment_shader_id)
1634	{
1635	    // Criamos um identificador (ID) para este programa de GPU
1636	    GLuint program_id = glCreateProgram();
1637	
1638	    // Definição dos dois shaders GLSL que devem ser executados pelo programa
1639	    glAttachShader(program_id, vertex_shader_id);
1640	    glAttachShader(program_id, fragment_shader_id);
1641	
1642	    // Linkagem dos shaders acima ao programa
1643	    glLinkProgram(program_id);
1644	
1645	    // Verificamos se ocorreu algum erro durante a linkagem
1646	    GLint linked_ok = GL_FALSE;
1647	    glGetProgramiv(program_id, GL_LINK_STATUS, &linked_ok);
1648	
1649	    // Imprime no terminal qualquer erro de linkagem
1650	    if ( linked_ok == GL_FALSE )
1651	    {
1652	        GLint log_length = 0;
1653	        glGetProgramiv(program_id, GL_INFO_LOG_LENGTH, &log_length);
1654	
1655	        // Alocamos memória para guardar o log de compilação.
1656	        // A chamada "new" em C++ é equivalente ao "malloc()" do C.
1657	        GLchar* log = new GLchar[log_length];
1658	
1659	        glGetProgramInfoLog(program_id, log_length, &log_length, log);
1660	
1661	        std::string output;
1662	
1663	        output += "ERROR: OpenGL linking of program failed.\n";
1664	        output += "== Start of link log\n";
1665	        output += log;
1666	        output += "\n== End of link log\n";
1667	
1668	        // A chamada "delete" em C++ é equivalente ao "free()" do C
1669	        delete [] log;
1670	
1671	        fprintf(stderr, "%s", output.c_str());
1672	    }
1673	
1674	    // Os "Shader Objects" podem ser marcados para deleção após serem linkados 
1675	    glDeleteShader(vertex_shader_id);
1676	    glDeleteShader(fragment_shader_id);
1677	
1678	    // Retornamos o ID gerado acima
1679	    return program_id;
1680	}
