1682	// Definição da função que será chamada sempre que a janela do sistema
1683	// operacional for redimensionada, por consequência alterando o tamanho do
1684	// "framebuffer" (região de memória onde são armazenados os pixels da imagem).
1685	void FramebufferSizeCallback(GLFWwindow* window, int width, int height)
1686	{
1687	    // Indicamos que queremos renderizar em toda região do framebuffer. A
1688	    // função "glViewport" define o mapeamento das "normalized device
1689	    // coordinates" (NDC) para "pixel coordinates".  Essa é a operação de
1690	    // "Screen Mapping" ou "Viewport Mapping" vista em aula ({+ViewportMapping2+}).
1691	    glViewport(0, 0, width, height);
1692	
1693	    // Atualizamos também a razão que define a proporção da janela (largura /
1694	    // altura), a qual será utilizada na definição das matrizes de projeção,
1695	    // tal que não ocorra distorções durante o processo de "Screen Mapping"
1696	    // acima, quando NDC é mapeado para coordenadas de pixels. Veja slides 205-215 do documento Aula_09_Projecoes.pdf.
1697	    //
1698	    // O cast para float é necessário pois números inteiros são arredondados ao
1699	    // serem divididos!
1700	    g_ScreenRatio = (float)width / height;
1701	}
