1756	// Função callback chamada sempre que o usuário movimentar o cursor do mouse em
1757	// cima da janela OpenGL.
1758	void CursorPosCallback(GLFWwindow* window, double xpos, double ypos)
1759	{
1760	    // No modo FPS o cursor está capturado: qualquer movimento vira a câmera
1761	    if (g_CameraMode == CAMERA_FPS)
1762	    {
1763	        float dx = xpos - g_LastCursorPosX;
1764	        float dy = ypos - g_LastCursorPosY;
1765	
1766	        const float sensitivity = 0.002f;
1767	        g_CameraTheta -= sensitivity * dx;
1768	        g_CameraPhi   -= sensitivity * dy; // dy positivo = mouse para baixo = olhar para baixo
1769	
1770	        float phimax = 3.141592f / 2.0f * 0.99f;
1771	        if (g_CameraPhi >  phimax) g_CameraPhi =  phimax;
1772	        if (g_CameraPhi < -phimax) g_CameraPhi = -phimax;
1773	
1774	        g_LastCursorPosX = xpos;
1775	        g_LastCursorPosY = ypos;
1776	        return;
1777	    }
1778	
1779	    if (g_LeftMouseButtonPressed)
1780	    {
1781	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1782	        float dx = xpos - g_LastCursorPosX;
1783	        float dy = ypos - g_LastCursorPosY;
1784	    
1785	        // Atualizamos parâmetros da câmera com os deslocamentos
1786	        g_CameraTheta -= 0.01f*dx;
1787	        g_CameraPhi   += 0.01f*dy;
1788	    
1789	        // Em coordenadas esféricas, o ângulo phi deve ficar entre -pi/2 e +pi/2.
1790	        float phimax = 3.141592f/2;
1791	        float phimin = -phimax;
1792	    
1793	        if (g_CameraPhi > phimax)
1794	            g_CameraPhi = phimax;
1795	    
1796	        if (g_CameraPhi < phimin)
1797	            g_CameraPhi = phimin;
1798	    
1799	        // Atualizamos as variáveis globais para armazenar a posição atual do
1800	        // cursor como sendo a última posição conhecida do cursor.
1801	        g_LastCursorPosX = xpos;
1802	        g_LastCursorPosY = ypos;
1803	    }
1804	
1805	    if (g_RightMouseButtonPressed)
1806	    {
1807	        // Deslocamento do cursor do mouse em x e y de coordenadas de tela!
1808	        float dx = xpos - g_LastCursorPosX;
1809	        float dy = ypos - g_LastCursorPosY;
1810	    
1811	        // Atualizamos parâmetros da antebraço com os deslocamentos
1812	        g_ForearmAngleZ -= 0.01f*dx;
1813	        g_ForearmAngleX += 0.01f*dy;
1814	    
1815	        // Atualizamos as variáveis globais para armazenar a posição atual do
1816	        // cursor como sendo a última posição conhecida do cursor.
1817	        g_LastCursorPosX = xpos;
1818	        g_LastCursorPosY = ypos;
1819	    }

