1838	// Função callback chamada sempre que o usuário movimenta a "rodinha" do mouse.
1839	void ScrollCallback(GLFWwindow* window, double xoffset, double yoffset)
1840	{
1841	    // Atualizamos a distância da câmera para a origem utilizando a
1842	    // movimentação da "rodinha", simulando um ZOOM.
1843	    g_CameraDistance -= 0.1f*yoffset;
1844	
1845	    // Uma câmera look-at nunca pode estar exatamente "em cima" do ponto para
1846	    // onde ela está olhando, pois isto gera problemas de divisão por zero na
1847	    // definição do sistema de coordenadas da câmera. Isto é, a variável abaixo
1848	    // nunca pode ser zero. Versões anteriores deste código possuíam este bug,
1849	    // o qual foi detectado pelo aluno Vinicius Fraga (2017/2).
1850	    const float verysmallnumber = std::numeric_limits<float>::epsilon();
1851	    if (g_CameraDistance < verysmallnumber)
1852	        g_CameraDistance = verysmallnumber;
1853	}
