1855	void Correcao_KeyCallback(int key, int action, int mod);
1856	
1857	// Definição da função que será chamada sempre que o usuário pressionar alguma
1858	// tecla do teclado. Veja http://www.glfw.org/docs/latest/input_guide.html#input_key
1859	void KeyCallback(GLFWwindow* window, int key, int scancode, int action, int mod)
1860	{
1861	    // =======================
1862	    // Não modifique esta chamada! Ela é utilizada para correção automatizada dos
1863	    // laboratórios. Deve ser sempre o primeiro comando desta função KeyCallback().
1864	    Correcao_KeyCallback(key, action, mod);
1865	    // =======================
1866	
1867	    // Se o usuário pressionar a tecla ESC, fechamos a janela.
1868	    if (key == GLFW_KEY_ESCAPE && action == GLFW_PRESS)
1869	        glfwSetWindowShouldClose(window, GL_TRUE);
1870	    
1871	    // O código abaixo implementa a seguinte lógica:
1872	    //   Se apertar tecla X       então g_AngleX += delta;
1873	    //   Se apertar tecla shift+X então g_AngleX -= delta;
1874	    //   Se apertar tecla Y       então g_AngleY += delta;
1875	    //   Se apertar tecla shift+Y então g_AngleY -= delta;
1876	    //   Se apertar tecla Z       então g_AngleZ += delta;
1877	    //   Se apertar tecla shift+Z então g_AngleZ -= delta;
1878	
1879	    float delta = 3.141592 / 16; // 22.5 graus, em radianos.
1880	
1881	    if (key == GLFW_KEY_X && action == GLFW_PRESS)
1882	    {
1883	        g_AngleX += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1884	    }
1885	
1886	    if (key == GLFW_KEY_Y && action == GLFW_PRESS)
1887	    {
1888	        g_AngleY += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1889	    }
1890	    if (key == GLFW_KEY_Z && action == GLFW_PRESS)
1891	    {
1892	        g_AngleZ += (mod & GLFW_MOD_SHIFT) ? -delta : delta;
1893	    }
1894	
1895	    // Se o usuário apertar a tecla espaço, resetamos os ângulos de Euler para zero.
1896	    if (key == GLFW_KEY_SPACE && action == GLFW_PRESS)
1897	    {
1898	        g_AngleX = 0.0f;
1899	        g_AngleY = 0.0f;
1900	        g_AngleZ = 0.0f;
1901	        g_ForearmAngleX = 0.0f;
1902	        g_ForearmAngleZ = 0.0f;
1903	        g_TorsoPositionX = 0.0f;
1904	        g_TorsoPositionY = 0.0f;
1905	    }
1906	
1907	    // Se o usuário apertar a tecla P, utilizamos projeção perspectiva.
1908	    if (key == GLFW_KEY_P && action == GLFW_PRESS)
1909	    {
1910	        g_UsePerspectiveProjection = true;
1911	    }
1912	
1913	    // Se o usuário apertar a tecla O, utilizamos projeção ortográfica.
1914	    if (key == GLFW_KEY_O && action == GLFW_PRESS)
1915	    {
1916	        g_UsePerspectiveProjection = false;
1917	    }
1918	
1919	    // Se o usuário apertar a tecla H, fazemos um "toggle" do texto informativo mostrado na tela.
1920	    if (key == GLFW_KEY_H && action == GLFW_PRESS)
1921	    {
1922	        g_ShowInfoText = !g_ShowInfoText;
1923	    }
1924	
1925	    // Se o usuário apertar a tecla R, recarregamos os shaders dos arquivos "shader_fragment.glsl" e "shader_vertex.glsl".
1926	    if (key == GLFW_KEY_R && action == GLFW_PRESS)
1927	    {
1928	        LoadShadersFromFiles();
1929	        fprintf(stdout,"Shaders recarregados!\n");
1930	        fflush(stdout);
1931	    }
1932	
1933	    // Tecla C alterna entre câmera FPS e câmera de segurança
1934	    if (key == GLFW_KEY_C && action == GLFW_PRESS)
1935	    {
1936	        if (g_CameraMode == CAMERA_FPS)
1937	        {
1938	            g_CameraMode = CAMERA_SECURITY;
1939	            glfwSetInputMode(window, GLFW_CURSOR, GLFW_CURSOR_NORMAL);
1940	        }
1941	        else
1942	        {
1943	            g_CameraMode = CAMERA_FPS;
1944	            glfwSetInputMode(window, GLFW_CURSOR, GLFW_CURSOR_DISABLED);
1945	            glfwGetCursorPos(window, &g_LastCursorPosX, &g_LastCursorPosY);
1946	        }
1947	    }
1948	
1949	    // Tecla 1-2 alterna entre movimento da câmera de segurança FollowPlayer-Bézier
1950	    if (key == GLFW_KEY_1 && action == GLFW_PRESS)
1951	    {
1952	        mov_sec_camera = 1;
1953	    }
1954	    if (key == GLFW_KEY_2 && action == GLFW_PRESS)
1955	    {
1956	        mov_sec_camera = 2;
1957	    }
1958	
1959	    // Alterna a lanterna
1960	    if (key == GLFW_KEY_F && action == GLFW_PRESS)
1961	    {
1962	        g_FlashlightEnabled = !g_FlashlightEnabled;
1963	    }
1964	    
1965	
1966	}
